import os

print('Workspace contents (should be ONLY this org):')
try:
    files = os.listdir('/workspace')
    for f in files:
        if not f.startswith('.'):
            print(f'  {f}')
    if not files or all(f.startswith('.') for f in files):
        print('  (empty — no notebooks opened yet)')
except PermissionError:
    print('  \u2705 Cannot access workspace')

print('\nCan see other org volumes?')
# In per-org containers, /workspace is a dedicated volume
# There are no other org directories visible
org_dirs = [f for f in os.listdir('/workspace') if f.startswith('org_')]
if org_dirs:
    print(f'  \u274c Found org directories: {org_dirs}')
    print('  This means old single-container mode or migration needed')
else:
    print('  \u2705 No org_ directories — per-org container isolation active')

import os

tests = []

# Try to write to system
try:
    with open('/etc/hacked', 'w') as f: f.write('no')
    os.remove('/etc/hacked')
    tests.append(('Write /etc', '\u274c ALLOWED'))
except (PermissionError, OSError):
    tests.append(('Write /etc', '\u2705 blocked'))

# Try to kill init
try:
    os.kill(1, 0)
    tests.append(('Signal PID 1', '\u274c ALLOWED'))
except PermissionError:
    tests.append(('Signal PID 1', '\u2705 blocked'))
except ProcessLookupError:
    tests.append(('Signal PID 1', '\u2705 no access'))

# Try to read shadow
try:
    open('/etc/shadow').read()
    tests.append(('Read /etc/shadow', '\u274c EXPOSED'))
except PermissionError:
    tests.append(('Read /etc/shadow', '\u2705 blocked'))

# Try to delete workspace
try:
    os.rmdir('/workspace')
    tests.append(('Delete /workspace', '\u274c ALLOWED'))
except OSError:
    tests.append(('Delete /workspace', '\u2705 blocked (not empty)'))

print('Destructive action tests:')
for name, status in tests:
    print(f'  {status:15} {name}')
